/* ============================================================
   md.js — Markdown parser for Zenjex docs
   Handles: headings, fenced code, blockquote, hr, tables,
            ul/ol lists (nested), paragraphs, inline formatting.
   Key invariant: code blocks are extracted FIRST so their
   content never confuses block-level detection.
   ============================================================ */
(function (root) {
  'use strict';

  function parse(src) {
    if (!src) return '';
    src = src.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    /* ── Phase 1: extract fenced code blocks ── */
    var blocks = [];
    src = src.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)\1[ \t]*$/gm,
      function (_, fence, lang, code) {
        var id = '\x00B' + blocks.length + '\x00';
        blocks.push({ lang: lang.trim(), code: code.replace(/\n$/, '') });
        return id;
      });

    /* ── Phase 2: parse line by line ── */
    var lines = src.split('\n');
    var out   = [];
    var i     = 0;

    while (i < lines.length) {
      var line = lines[i];

      /* Code block placeholder */
      if (/^\x00B\d+\x00$/.test(line.trim())) {
        var idx  = parseInt(line.match(/\d+/)[0], 10);
        var b    = blocks[idx];
        var lang = b.lang;
        if (lang === 'flow') {
          out.push(buildFlowDiagram(b.code));
        } else if (lang === 'timeline') {
          out.push(buildTimelineDiagram(b.code));
        } else if (lang === 'api') {
          out.push(buildApiSurface(b.code));
        } else {
          var cls  = lang ? ' class="language-' + esc(lang) + '"' : '';
          var badge = (lang === 'csharp' || lang === 'cs') ? '<div class="wiki-code-lang">C#</div>' : '';
          out.push('<div class="wiki-code-wrap">' + badge + '<pre><code' + cls + '>' + esc(b.code) + '</code></pre></div>');
        }
        i++; continue;
      }

      /* Heading */
      var hm = line.match(/^(#{1,6})[ \t]+(.+)/);
      if (hm) {
        var lvl  = hm[1].length;
        var htxt = inline(hm[2].trim());
        var hid  = hm[2].trim().toLowerCase().replace(/[^\wа-яёА-ЯЁ\s-]/g, '').replace(/\s+/g, '-');
        out.push('<h' + lvl + ' id="' + esc(hid) + '">' + htxt + '</h' + lvl + '>');
        i++; continue;
      }

      /* Horizontal rule */
      if (/^[ \t]{0,3}([-*_])[ \t]*\1[ \t]*\1[ \t]*$/.test(line)) {
        out.push('<hr>');
        i++; continue;
      }

      /* Blockquote */
      if (/^[ \t]*>/.test(line)) {
        var bqLines = [];
        while (i < lines.length && /^[ \t]*>/.test(lines[i])) {
          bqLines.push(lines[i].replace(/^[ \t]*>[ \t]?/, ''));
          i++;
        }
        out.push('<blockquote>' + parse(bqLines.join('\n')) + '</blockquote>');
        continue;
      }

      /* Table: header line followed by separator line */
      if (line.includes('|')) {
        var nextNonEmpty = i + 1;
        while (nextNonEmpty < lines.length && lines[nextNonEmpty].trim() === '') nextNonEmpty++;
        if (nextNonEmpty < lines.length && /^\|?[ \t]*:?-+:?[ \t]*(\|[ \t]*:?-+:?[ \t]*)+\|?$/.test(lines[nextNonEmpty].trim())) {
          var tblLines = [];
          while (i < lines.length && lines[i].includes('|')) {
            tblLines.push(lines[i]);
            i++;
          }
          out.push(buildTable(tblLines));
          continue;
        }
      }

      /* List (unordered or ordered) */
      if (/^[ \t]{0,3}[-*+][ \t]/.test(line) || /^[ \t]{0,3}\d+[.)]\s/.test(line)) {
        var listLines = [];
        var baseIndent = line.match(/^([ \t]*)/)[1].length;
        while (i < lines.length) {
          var l = lines[i];
          /* continuation: indented lines, blank lines inside list, or new list items */
          if (l.trim() === '') {
            /* blank line — include only if next is still a list item */
            if (i + 1 < lines.length && (/^[ \t]{0,3}[-*+][ \t]/.test(lines[i+1]) || /^[ \t]{0,3}\d+[.)]\s/.test(lines[i+1]) || /^[ \t]{2,}/.test(lines[i+1]))) {
              listLines.push(l); i++; continue;
            }
            break;
          }
          if (/^[ \t]{0,3}[-*+][ \t]/.test(l) || /^[ \t]{0,3}\d+[.)]\s/.test(l) || /^[ \t]{2,}/.test(l)) {
            listLines.push(l); i++; continue;
          }
          break;
        }
        out.push(buildList(listLines));
        continue;
      }

      /* Blank line */
      if (line.trim() === '') { i++; continue; }

      /* Paragraph */
      var paraLines = [];
      while (i < lines.length) {
        var pl = lines[i];
        if (pl.trim() === '') break;
        if (/^(#{1,6})[ \t]/.test(pl)) break;
        if (/^[ \t]{0,3}([-*_])[ \t]*\1[ \t]*\1[ \t]*$/.test(pl)) break;
        if (/^[ \t]*>/.test(pl)) break;
        if (/^[ \t]{0,3}[-*+][ \t]/.test(pl)) break;
        if (/^[ \t]{0,3}\d+[.)]\s/.test(pl)) break;
        if (/^\x00B\d+\x00$/.test(pl.trim())) break;
        paraLines.push(pl);
        i++;
      }
      if (paraLines.length) {
        out.push('<p>' + inline(paraLines.join(' ')) + '</p>');
      }
    }

    return out.join('\n');
  }

  /* ── Table builder ── */
  function buildTable(lines) {
    /* Filter out separator rows */
    var dataRows = lines.filter(function (l) {
      return !/^\|?[ \t]*:?-+:?[ \t]*(\|[ \t]*:?-+:?[ \t]*)*\|?$/.test(l.trim());
    });
    if (!dataRows.length) return '';

    var parseRow = function (l) {
      return l.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map(function (c) { return c.trim(); });
    };

    var header = parseRow(dataRows[0]);
    var body   = dataRows.slice(1);

    var ths = header.map(function (c) { return '<th>' + inline(c) + '</th>'; }).join('');
    var trs = body.map(function (r) {
      return '<tr>' + parseRow(r).map(function (c) { return '<td>' + inline(c) + '</td>'; }).join('') + '</tr>';
    }).join('\n');

    return '<div class="wiki-table-wrap"><table><thead><tr>' + ths + '</tr></thead><tbody>' + trs + '</tbody></table></div>';
  }

  /* ── List builder (handles nested lists) ── */
  function buildList(lines) {
    /* Detect ordered by first item */
    var ordered = /^[ \t]{0,3}\d+[.)]\s/.test(lines[0]);
    var tag = ordered ? 'ol' : 'ul';

    var items = [];
    var current = null;

    lines.forEach(function (line) {
      if (line.trim() === '') return;
      /* Top-level list item */
      if (/^[ \t]{0,3}[-*+][ \t]/.test(line) || /^[ \t]{0,3}\d+[.)]\s/.test(line)) {
        if (current !== null) items.push(current);
        current = { text: line.replace(/^[ \t]{0,3}(?:[-*+]|\d+[.)])\s+/, ''), children: [] };
      } else if (current !== null) {
        /* Continuation / nested content */
        current.children.push(line.replace(/^[ \t]{2,4}/, ''));
      }
    });
    if (current !== null) items.push(current);

    var html = '<' + tag + '>';
    items.forEach(function (item) {
      html += '<li>' + inline(item.text);
      if (item.children.length) {
        /* Check if children contain nested list items */
        var hasNested = item.children.some(function (c) {
          return /^[-*+][ \t]/.test(c) || /^\d+[.)]\s/.test(c);
        });
        if (hasNested) html += buildList(item.children);
        /* else: plain continuation text — skip (already in parent text) */
      }
      html += '</li>';
    });
    html += '</' + tag + '>';
    return html;
  }

  /* ── Inline formatter ── */
  function inline(src) {
    if (!src) return '';
    return src
      /* Inline code — protect first */
      .replace(/`([^`]+)`/g, function (_, c) { return '<code>' + esc(c) + '</code>'; })
      /* Bold */
      .replace(/\*\*([^*\n]+)\*\*/g, '<strong>$1</strong>')
      .replace(/__([^_\n]+)__/g, '<strong>$1</strong>')
      /* Italic */
      .replace(/\*([^*\n]+)\*/g, '<em>$1</em>')
      .replace(/_([^_\n]+)_/g, '<em>$1</em>')
      /* Links */
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, function (_, text, href) {
        var ext = /^https?:\/\//.test(href);
        return '<a href="' + esc(href) + '"' + (ext ? ' target="_blank" rel="noopener"' : '') + '>' + text + '</a>';
      })
      /* Images */
      .replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1">');
  }

  function esc(s) {
    return String(s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }


  /* ════════════════════════════════════════════════════════════
     FLOW DIAGRAM
     Format per line:
       Label | note          — top-level step
         SubLabel | note     — child step (2+ spaces indent)
     ════════════════════════════════════════════════════════════ */
  function buildFlowDiagram(src) {
    var lines = src.split('\n').filter(function(l){ return l.trim(); });
    // Group into top-level items with optional children
    var items = [];
    lines.forEach(function(line) {
      var indent = line.match(/^(\s*)/)[1].length;
      var parts  = line.trim().split('|');
      var label  = (parts[0] || '').trim();
      var note   = (parts[1] || '').trim();
      if (indent === 0) {
        items.push({ label: label, note: note, children: [] });
      } else if (items.length) {
        items[items.length - 1].children.push({ label: label, note: note });
      }
    });

    var html = '<div class="dgm-flow">';
    items.forEach(function(item, idx) {
      var isLast = idx === items.length - 1;
      html += '<div class="dgm-flow-item">';
      html += '<div class="dgm-flow-connector">';
      html += '<div class="dgm-flow-dot"></div>';
      if (!isLast || item.children.length) html += '<div class="dgm-flow-line"></div>';
      html += '</div>';
      html += '<div class="dgm-flow-content">';
      if (item.label) html += '<div class="dgm-flow-label"><code>' + esc(item.label) + '</code></div>';
      if (item.note)  html += '<div class="dgm-flow-note">' + esc(item.note) + '</div>';
      if (item.children.length) {
        html += '<div class="dgm-flow-children">';
        item.children.forEach(function(c, ci) {
          var cLast = ci === item.children.length - 1;
          html += '<div class="dgm-flow-item">';
          html += '<div class="dgm-flow-connector">';
          html += '<div class="dgm-flow-dot dgm-flow-dot--child"></div>';
          if (!cLast) html += '<div class="dgm-flow-line"></div>';
          html += '</div>';
          html += '<div class="dgm-flow-content">';
          if (c.label) html += '<div class="dgm-flow-label"><code>' + esc(c.label) + '</code></div>';
          if (c.note)  html += '<div class="dgm-flow-note">' + esc(c.note) + '</div>';
          html += '</div></div>';
        });
        html += '</div>';
      }
      html += '</div></div>';
    });
    html += '</div>';
    return html;
  }

  /* ════════════════════════════════════════════════════════════
     TIMELINE DIAGRAM
     Format:
       [Group Label]
       ItemLabel | note
       ItemLabel | note
     ════════════════════════════════════════════════════════════ */
  function buildTimelineDiagram(src) {
    var lines = src.split('\n').filter(function(l){ return l.trim(); });
    var html  = '<div class="dgm-timeline">';
    var currentGroup = null;
    var items = [];

    function flushGroup() {
      if (!currentGroup && !items.length) return;
      if (currentGroup) {
        html += '<div class="dgm-tl-group">';
        html += '<div class="dgm-tl-group-label">' + esc(currentGroup) + '</div>';
        html += '<div class="dgm-tl-items">';
      }
      items.forEach(function(item, idx) {
        var isLast = idx === items.length - 1;
        html += '<div class="dgm-tl-item">';
        html += '<div class="dgm-tl-connector"><div class="dgm-tl-dot"></div>';
        if (!isLast) html += '<div class="dgm-tl-line"></div>';
        html += '</div>';
        html += '<div class="dgm-tl-body"><div class="dgm-tl-row">';
        html += '<code class="dgm-tl-label">' + esc(item.label) + '</code>';
        html += '</div>';
        if (item.note) html += '<div class="dgm-tl-sub">' + esc(item.note) + '</div>';
        html += '</div></div>';
      });
      if (currentGroup) html += '</div></div>';
      items = [];
    }

    lines.forEach(function(line) {
      var grpMatch = line.trim().match(/^\[(.+)\]$/);
      if (grpMatch) {
        flushGroup();
        currentGroup = grpMatch[1];
        return;
      }
      var parts = line.trim().split('|');
      items.push({ label: (parts[0]||'').trim(), note: (parts[1]||'').trim() });
    });
    flushGroup();
    html += '</div>';
    return html;
  }

  /* ════════════════════════════════════════════════════════════
     API SURFACE
     Format per line:  ReturnType | MethodSignature | optional note
     ════════════════════════════════════════════════════════════ */
  function buildApiSurface(src) {
    var lines = src.split('\n').filter(function(l){ return l.trim(); });
    var html = '<div class="wiki-api-surface">';
    lines.forEach(function(line) {
      var parts = line.split('|');
      var ret  = (parts[0] || '').trim();
      var sig  = (parts[1] || '').trim();
      var note = (parts[2] || '').trim();
      if (!sig) return;
      html += '<div class="wiki-api-row">';
      html += '<span class="wiki-api-ret"><code>' + esc(ret) + '</code></span>';
      html += '<span class="wiki-api-sig"><code>' + esc(sig) + '</code></span>';
      if (note) html += '<span class="wiki-api-note">' + esc(note) + '</span>';
      html += '</div>';
    });
    html += '</div>';
    return html;
  }

  var marked = { parse: parse };

  if (typeof module !== 'undefined' && module.exports) module.exports = marked;
  else root.marked = marked;

}(typeof globalThis !== 'undefined' ? globalThis : typeof window !== 'undefined' ? window : this));
